/**
 * CORE-004 — Zod canonical source for the gate-result schema.
 *
 * Generated artifact: `src/schemas/runtime/gate-result.schema.json`
 * (regenerated by `npm run schemas:generate`, validated in CI by
 * `npm run schemas:check`).
 *
 * Runtime continues to consume the .schema.json via Ajv in
 * `src/runtime/subagent-runner.ts` — this file becomes the source of
 * truth, not a runtime hot path.
 */
import { z } from "zod";

export const GateResultSchema = z
  .object({
    verdict: z.enum(["pass", "fail"]),
    check_id: z.string().min(1),
    summary: z.string().optional(),
    evidence: z.record(z.string(), z.unknown()).optional(),
    suggested_action: z.string().optional(),
    tokens_consumed: z.int().min(0).optional(),
  })
  .strict();

export type GateResult = z.infer<typeof GateResultSchema>;
